<script lang="ts" setup>
import { Auth } from '@/src/http'

defineProps<{
  disabled?: boolean
}>()

const showIssueMessage = useTimeout(3000)

async function probeAccount() {
  if (!isChromePopup()) {
    const email = Object.keys(Auth.state.users)?.[0]

    if (email)
      Auth.setAccount(email)

    return
  }

  const [tab] = await browser.tabs.query({ active: true, currentWindow: true })

  chrome.tabs.sendMessage(tab.id!, 'get-active-email', (email: string) => {
    if (email)
      Auth.setAccount(email)

    else setTimeout(probeAccount, 1500)
  })
}

onMounted(probeAccount)
</script>

<template>
  <slot v-if="disabled || Auth.activeEmail.value" />

  <div v-else class="size-screen gap-4 flex-col-center">
    <img
      src="@/assets/logo.svg"
      alt=""
      width="64"
      height="64"
      draggable="false"
    >

    <h3 class="text-neutral/70 flex-center">
      <Spinner size="xs" class="text-primary -ml-2 mr-2" />
      Waiting for connection
    </h3>

    <Transition name="fade" mode="out-in">
      <div v-if="showIssueMessage" class="mt-10 p-4 rounded-lg bg-primary/3 text-sm shadow-sm border-1 border-dashed border-primary">
        <h4 class="font-medium">
          Having issues?
        </h4>

        <p class="opacity-67">
          You can try reloading the extension and gmail page
        </p>

        <CTAButton variant="primary" class="mt-6 ml-auto" @click="reloadApp">
          Reload
        </CTAButton>
      </div>
    </Transition>
  </div>
</template>
