import { createControlledPromise } from '@antfu/utils'

export const PopupSize = {
  Normal: {
    width: 400,
    height: 700
  },

  get Large() {
    const min = (...args: number[]) => Math.round(Math.min(...args))

    return {
      width: min(screen.width * 0.7, 985),
      height: min(screen.width * 0.5, 800)
    }
  }
}

export function openPopup(url: string, { size = PopupSize.Normal } = {}) {
  const onclose = createControlledPromise<void>()
  const x = (screen.width - size.width) / 2
  const y = (screen.height - size.height) / 2

  const popup = window.open(url, '_blank', `width=${size.width},height=${size.height},left=${x},top=${y}`)

  const timer = setInterval(() => {
    if (!popup?.closed)
      return

    clearInterval(timer)
    onclose.resolve()
  }, 1500)

  return onclose
}

export async function animateDOM(callback: VoidFunction) {
  try {
    (document as any).startViewTransition(() => {
      callback()
    })
  }

  catch (error: unknown) {
    console.error(error)
    callback()
  }
}
