<script lang="ts" setup>
const user = useSession()
const route = useRoute()
const authorized = computed(() => user.isLoggedIn || route.meta.auth === false)
</script>

<template>
  <PopupAuthScope :disabled="authorized">
    <RouterView v-slot="{ Component }">
      <Transition name="fade" mode="out-in">
        <component :is="Component" v-if="authorized" />

        <div v-else class="size-screen flex-center">
          <Login />
        </div>
      </Transition>
    </RouterView>
  </PopupAuthScope>
</template>
