<script lang="ts" setup>
const props = defineProps<{
  variant?: 'primary' | 'neutral'
  label?: string
  icon?: string
  loading?: boolean
  onClick?: () => any | Promise<any>
}>()

const isResolving = ref(false)

async function handleClick() {
  const fn = props.onClick

  if (!fn)
    return

  isResolving.value = true
  await fn()
  isResolving.value = false
}

const colorVariants = {
  primary: 'bg-primary hover:bg-primary/95 text-white',
  neutral: 'bg-hex-F1F1F1',
  none: null
}
</script>

<template>
  <button
    class="h-32px px-3 gap-3 flex items-center rounded-md active:scale-97 ![&[inert]]:opacity-70"
    :class="[colorVariants[variant ?? 'none']]"
    :inert="loading || isResolving"
    @click="handleClick"
  >
    <Spinner v-if="loading || isResolving" size="xs" />
    <span v-else-if="icon" class="size-4" :class="icon" />

    <slot>
      {{ label }}
    </slot>
  </button>
</template>

<style scoped lang="sass">
.variant-primary
  @apply bg-primary

//;
</style>
