import { Auth, Blacklist, http, User } from '@/src/http'
import { setSentryUser } from '@/src/vue'

const openLargePopup = (url: string) => openPopup(url, { size: PopupSize.Large })

/** Global extension settings */
export const useSettings = createSharedComposable(() =>
  useChromeStore('local:app-settings', {
    /** Whether automatic draft generation is enabled */
    autoDraft: true
  })
)

export const useUser = defineStore('user', {
  state: () => User.Model
    .parse({
      id: -1,
      email: 'display@autogmail.com'
    }),

  getters: {
    isReady: () => Auth.state.$isReady as unknown as boolean,
    isLoggedIn: () => !!Auth.user.value
  },

  actions: {
    async sync() {
      this.$patch(await User.get())
      return this.$state
    },

    async signin() {
      try {
        await openPopup(
          getRouteURL(`/auth/google?login_email=${Auth.activeEmail.value}`)
        )

        await this.sync()
        return this.isLoggedIn
      }
      catch (error) {
        console.error('Failed to login', { error })
        return false
      }
    },

    async signout() {
      Auth.logout()
      this.$reset()
      Analytics.track('Signed out')
    },

    async updateContext(context: string, aiTips?: string[]) {
      const result = await http
        .post({ context, ai_tips: aiTips }, '/chrome-context')
        .json<{ success: boolean }>()

      await this.sync()
      Analytics.track('Updated context', { context, aiTips })

      return result.success
    },

    async toggleAI(enabled: boolean) {
      Analytics.track('Toggled AI', { enabled })

      await http.url('/switch').formData({ enabled }).post()
      await this.sync()
      return this.enabled
    },

    /** blocks/unblocks email address */
    async toggleBlacklist(email: string) {
      await Blacklist.toggle(email)
      await this.sync()
    },

    async connectGmail() {
      try {
        await openLargePopup(
          getAPIURL('/chrome/connect/gmail')
        )

        await this.sync()
        Analytics.track('Connected gmail account', { success: this.connected })

        return this.connected
      }
      catch {
        return false
      }
    },

    /** Opens stripe flow */
    async subscribe(plan: 'monthly' | 'yearly' = 'monthly', trial = false) {
      await this.sync()

      // Return if already subscribed
      if (this.subscribed)
        return true

      const params = {
        plan,
        trial,
        email: Auth.activeEmail.value
      }

      Analytics.track('Opened subscription page', params)
      await openLargePopup(getRouteURL(`/payment`, params))
      await this.sync()

      return this.subscribed
    },

    async openPaymentPage() {
      Analytics.track('Clicked upgrade button')
      return this.subscribe('monthly')
    },

    async openSubscriptionPage() {
      const { url } = await http.get('/chrome-manage-subscription').json<{ url: string }>()
      await openLargePopup(url)
      await this.sync()
    }
  }
})

/** Sync handler for {@link useUser} */
export const useSession = createSharedComposable(() => {
  const user = useUser()

  // Receive changes
  Auth.onChange((account) => {
    // Logout
    if (!account)
      return user.$reset()

    const { data } = account

    // Update diagnostics
    if (data.email !== user.email) {
      setSentryUser(data)
      Analytics.identify(data)
    }

    // Update user store
    user.$patch(data)
  }, { immediate: true })

  // Push changes
  user.$subscribe((mutation, state) => {
    Auth.updateUserData(state)
  })

  return user
})
