import type { PiniaPlugin, PiniaPluginContext } from 'pinia'
import { isDeepEqual } from '@antfu/utils'

declare module 'pinia' {
  export interface PiniaCustomProperties {
    /** Whether initial data is ready */
    $hasInitialData: boolean
  }
}

class Storage {
  constructor(
    public context: PiniaPluginContext,
    public provider = chrome.storage.local,
    readonly key = context.store.$id
  ) { }

  dataset = {}

  async get() {
    const dataset = await this.provider.get(this.key)
    return this.dataset = dataset[this.key] ?? {}
  }

  async set(state: unknown) {
    const data = sanitizeJSON<any>(state)

    if (isDeepEqual(data, this.dataset))
      return

    console.debug(`⬆️ Updating chrome store: ${this.key}`, { data })
    this.provider.set({ [this.key]: this.dataset = data })
  }

  watch(callback: (data: object) => void) {
    this.provider.onChanged.addListener(async () => {
      const store = await this.provider.get()
      const data = store[this.key] ?? {}

      if (isDeepEqual(data, this.dataset))
        return

      console.debug('⬇️ Received data change from chrome', { data })
      callback(this.dataset = data)
    })
  }
}

export function ChromePersist(): PiniaPlugin {
  return (context) => {
    const { store } = context
    const storage = new Storage(context)
    const hasInitialData = ref(false)

    // @ts-expect-error type issue
    store.$hasInitialData = hasInitialData

    // Hydrate initial value
    storage.get().then((data) => {
      console.log('Patching initial data', { data })
      store.$patch(data)
      hasInitialData.value = true
    })

    // Watch store
    store.$subscribe((mutation, state) => storage.set(state))
    storage.watch(data => store.$patch(data))
  }
}

export function usePinia() {
  return createPinia()
}
