import { createControlledPromise, debounce } from '@antfu/utils'
import { ref, shallowRef } from 'vue'

/** Debounces a promise until completion */
export function promiseDebounce<R, Fn extends (...args: any[]) => Promise<R>>(fn: Fn): Fn {
  let pending: Promise<R>

  const runner = (...args: Parameters<Fn>) => {
    if (pending)
      return pending

    pending = fn(...args) as any
    pending.finally(() => pending = null as any)

    return pending
  }

  return runner as Fn
}

export function usePromise<R, Fn extends (...args: any[]) => Promise<R>>(defaultValue: R, fn: Fn, config: {
  onGetResult?: (data: R) => void
  debounce?: number
} = {}) {
  /** Whether first refresh has been called */
  const isReady = ref(false)

  /** Whether refresh is pending */
  const isLoading = ref(false)

  const data = shallowRef(defaultValue)

  const runner = promiseDebounce(async (...args: any[]) => {
    isLoading.value = true
    const result = await fn(...args)

    isReady.value = false
    isLoading.value = false

    config.onGetResult?.(result)

    return data.value = result
  }) as Fn

  const refresh = config.debounce ? debounce(config.debounce, runner) : runner

  return { isReady, isLoading, data, refresh }
}

export function useAsyncTasks() {
  let promise = Promise.resolve()

  function run(callback: () => Promise<void>) {
    promise = promise.then(callback)
  }

  return {
    run,

    get promise() {
      return promise
    }
  }
}

/** Returns a file from user selection */
export async function chooseFile({
  accept = '*'
} = {}): Promise<File> {
  const promise = createControlledPromise<File>()

  const input = document.createElement('input')
  input.type = 'file'
  input.accept = accept

  input.onchange = () => {
    const file = input.files?.[0]

    if (file)
      promise.resolve(file)

    else promise.reject(new Error('No file selected'))
  }

  input.click()

  return promise
}
