import type { WatchOptions } from 'vue'
import { computed } from 'vue'
import wretch from 'wretch'

import FormDataAddon from 'wretch/addons/formData'
import QueryAddon from 'wretch/addons/queryString'
import { User } from './api'

/** Origin of backend */
export const API_BASE = import.meta.env.VITE_APP_API_BASE
export const baseHTTP = wretch(API_BASE)
  .addon(QueryAddon)
  .addon(FormDataAddon)

export class Auth {
  static state = useChromeStore('local:accounts', {
    users: {} as { [email: string]: User.IAccountModel }
  }, {
    version: 2,
    migrations: {
      2: (dataset) => {
        const state = {
          users: {} as Record<string, User.IAccountModel>
        }

        const users = dataset?.users as User.IAccountModel[]

        if (!Array.isArray(users))
          return dataset

        Object.values(users).forEach((entry) => {
          state.users[entry.email] = entry
        })

        return state
      }
    }
  })

  static activeEmail = ref<string>()
  static user = computed(() => this.activeEmail.value ? this.state.users[this.activeEmail.value] : null)

  static onChange(callback: (account: User.IAccountModel | null) => void, options?: WatchOptions) {
    return watch([this.state, this.activeEmail], () => callback(this.user.value), options)
  }

  static logout() {
    const email = this.activeEmail.value

    if (email)
      delete this.state.users[email]

    console.debug('Logged out of email:', email)
  }

  static async login(email: string, params: Partial<User.IAccountModel>) {
    await this.state.users.$onLoaded

    const data = await baseHTTP
      .auth(`Bearer ${params.accessToken}`)
      .get('/chrome-account')
      .json(User.Model.parse)

    this.state.users[email] = User.AccountModel.parse({ ...params, data })
    this.setAccount(email)

    return true
  }

  static setAccount(email: string) {
    this.activeEmail.value = email
    console.debug('Using user account:', email)

    if (chrome.cookies) {
      console.debug('Updated backend auth cookie')

      chrome.cookies.set({
        url: API_BASE,
        name: 'access_token_cookie',
        secure: true,
        httpOnly: true,
        value: Auth.user.value?.accessToken
      })
    }
  }

  /** Updates user data in rective state */
  static updateUserData(data: User.IModel) {
    Object.values(this.state.users).forEach((account) => {
      if (account?.data?.email === data.email)
        account.data = data
    })
  }

  static createLoginURL(redirect?: string) {
    const url = new URL(`${API_BASE}/chrome/login`)
    const params = url.searchParams
    const hint = this.activeEmail.value

    if (redirect)
      params.set('redirect', redirect)

    if (hint)
      params.set('hint', hint)

    return url.href
  }

  /** Creates an url that automatically logins the user to the server */
  static getAuthRedirect(path: string, backend = true) {
    const token = this.user.value?.accessToken

    if (!token) {
      this.logout()
      throw new Error('No access token is available')
    }

    // Assign backend origin if it's a backend url
    if (backend)
      path = new URL(path, API_BASE).href

    const url = new URL(`${API_BASE}/chrome/auth-redirect`)
    url.searchParams.set('access-token', token)
    url.searchParams.set('url', path)

    return url.href
  }
}

/** Wretch client with included credentials */
export const http = baseHTTP
  .options({
    mode: 'cors',
    credentials: 'include',
    headers: {
      get Authorization() {
        return `Bearer ${Auth.user.value?.accessToken}`
      }
    }
  })
  // Handle auth
  .catcherFallback((error) => {
    if ([401, 422].includes(error.status)) {
      Auth.logout()
      throw new Error('User logged out', { cause: error })
    }
  })
  .resolve(chain => chain)
