import type { StorageItemKey, WxtStorageItemOptions } from 'wxt/storage'
import { isDeepEqual, throttle } from '@antfu/utils'

export function useChromeStore<T extends object>(key: StorageItemKey, value: T, options: WxtStorageItemOptions<T> = {}) {
  const state = reactive(value)
  const storageRef = storage.defineItem<T>(key, {
    init: () => value,
    ...options
  })

  const sync = throttle(250, (value: T | null) => {
    const shouldUpdate = !isDeepEqual(value, state)

    if (import.meta.env.DEV) {
      console.debug('useChromeStore: sync', {
        value: sanitizeJSON(value),
        state: sanitizeJSON(state),
        shouldUpdate
      })
    }

    if (value && shouldUpdate)
      Object.assign(state, value)
  })

  function createWatcher() {
    watchEffect(() => {
      const data = sanitizeJSON<any>(state)
      storageRef.setValue(data)
    })
  }

  // Load initial value
  const $isReady = shallowRef(false)
  const $onLoaded = storageRef.getValue().then(sync).finally(() => {
    $isReady.value = true
    createWatcher()
  })

  // Watch for changes
  storageRef.watch(sync)

  return Object.assign(state, {
    $isReady,
    $onLoaded
  })
}

export function isChromePopup() {
  return chrome.extension.getViews({ type: 'popup' }).includes(window)
}

export function useChromePopupSize(width: number, height = 556) {
  if (!isChromePopup())
    return

  function resize(w: number, h: number) {
    Object.assign(document.documentElement.style, {
      minWidth: `${w}px`,
      minHeight: `${h}px`
    })
  }

  onMounted(() => resize(width, height))

  onBeforeUnmount(() => resize(756, 556))
}

export function sanitizeJSON<T>(data: T): T {
  return JSON.parse(JSON.stringify(data))
}
