import { createSentryApp, usePinia } from '@/src/vue'
import { setupLayouts } from 'virtual:generated-layouts'

import { createRouter, createWebHashHistory, RouterView } from 'vue-router/auto'
import { routes } from 'vue-router/auto-routes'

import './style.sass'
import 'uno.css'

const router = createRouter({
  history: createWebHashHistory(),
  routes: setupLayouts(routes)
})

createSentryApp(RouterView)
  .use(usePinia())
  .use(router)
  .mount('#app')
